('Triathlon Race Week Preparation Protocol',
 'cardiovascular', array['quads','glutes','shoulder'], array['cardiovascular','quads','glutes'],
 'sport_specific', 'cardio', array['all_gear','transition_bag'], 'intermediate', true,
 'Structured race week for Olympic distance triathlon. Monday: rest. Tuesday: 30min swim drills + 30min easy bike. Wednesday: 20min easy run + mobility. Thursday: 20min swim race pace efforts + 20min bike activation. Friday: rest + gear check + transition bag pack. Saturday: 10min swim (if available) + 20min easy bike + 10min easy run + 3x20s race pace strides. Race day Sunday.',
